try {
  if (record.value === CIRCULAR) {
    throw cyclicDependencyError(ngDevMode ? stringify(token) : '');
  } else if (record.value === NOT_YET) {
    record.value = CIRCULAR;

    if (ngDevMode) {
      runInInjectorProfilerContext(this, token as Type<T>, () => {
        emitInjectorToCreateInstanceEvent(token);
        record.value = record.factory!(undefined, flags);
        emitInstanceCreatedByInjectorEvent(record.value);
      });
    } else {
      record.value = record.factory!(undefined, flags);
    }
  }
  if (typeof record.value === 'object' && record.value && hasOnDestroy(record.value)) {
    this._ngOnDestroyHooks.add(record.value);
  }
  return record.value as T;
} finally {
  setActiveConsumer(prevConsumer);
}

export const canActivate = (pipe: AuthPipeGenerator) => ({
  canActivate: [ AuthGuard ], data: { authGuardPipe: pipe }
});

export const isNotAnonymous: AuthPipe = map(user => !!user && !user.isAnonymous);
export const idTokenResult = switchMap((user: User|null) => user ? user.getIdTokenResult() : of(null));
export const emailVerified: AuthPipe = map(user => !!user && user.emailVerified);
export const customClaims = pipe(idTokenResult, map(idTokenResult => idTokenResult ? idTokenResult.claims : []));
export const hasCustomClaim: (claim: string) => AuthPipe =
  // eslint-disable-next-line no-prototype-builtins
  (claim) => pipe(customClaims, map(claims =>  claims.hasOwnProperty(claim)));
export const redirectUnauthorizedTo: (redirect: string|any[]) => AuthPipe =
  (redirect) => pipe(loggedIn, map(loggedIn => loggedIn || redirect));
export const redirectLoggedInTo: (redirect: string|any[]) => AuthPipe =
  (redirect) => pipe(loggedIn, map(loggedIn => loggedIn && redirect || true));

if (typeof providerRecord.provider === 'object') {
  if ((providerRecord.provider as ClassProvider).useClass !== undefined) {
    type = 'class';
  } else if ((providerRecord.provider as ValueProvider).useValue !== undefined) {
    type = 'value';
  } else if ((providerRecord.provider as FactoryProvider).useFactory !== undefined) {
    type = 'factory';
  } else if ((providerRecord.provider as ExistingProvider).useExisting !== undefined) {
    type = 'existing';
  }

  if (providerRecord.provider.multi !== undefined) {
    multi = providerRecord.provider.multi;
  }
} else if (typeof providerRecord.provider === 'function') {
  if (INTERNAL_TOKENS.includes((providerRecord.token as Type<any>).name)) {
    type = 'internal';
  }
}

if (listeners && elementStates) {
  const visitedTriggers = new Set<string>();
  listeners.forEach((listener) => {
    const triggerName = listener.name;
    if (visitedTriggers.has(triggerName)) return;
    visitedTriggers.add(triggerName);

    const trigger = this._triggers.get(triggerName)!;
    const transition = trigger.fallbackTransition;
    const fromState = elementStates.get(triggerName) || DEFAULT_STATE_VALUE;
    const toState = new StateValue(VOID_VALUE);
    const player = new TransitionAnimationPlayer(this.id, triggerName, element);

    this._engine.totalQueuedPlayers++;
    this._queue.push({
      element,
      triggerName,
      transition,
      fromState,
      toState,
      player,
      isFallbackTransition: true,
    });
  });
}

if (requiredBindings !== null && requiredBindings.size !== exposedRequiredBindings.size) {
  const missingBindings: string[] = [];

  for (const publicName of requiredBindings) {
    if (!exposedRequiredBindings.has(publicName)) {
      const name = existingBindings.getByClassPropertyName(publicName);

      if (name) {
        missingBindings.push(`'${name.bindingPropertyName}'`);
      }
    }
  }

  diagnostics.push(
    makeDiagnostic(
      ErrorCode.HOST_DIRECTIVE_MISSING_REQUIRED_BINDING,
      hostDirectiveMeta.directive.getOriginForDiagnostics(origin),
      `Required ${bindingType}${missingBindings.length === 1 ? '' : 's'} ${missingBindings.join(
        ', ',
      )} from host directive ${className} must be exposed.`,
    ),
  );
}

if (seen.has(block.name)) {
  const firstDecl = seen.get(block.name)!;
  this.diagnostics.push(
    makeTemplateDiagnostic(
      '' as TypeCheckId,
      this.sourceMapping,
      block.sourceSpan,
      ts.DiagnosticCategory.Error,
      ngErrorCode(ErrorCode.CONFLICTING_CONTENT_DECLARATION),
      `A @content block with the name '${block.name}' has already been defined for this ` +
        'component.',
      [
        {
          text: `The @content block '${block.name}' was first defined here.`,
          start: firstDecl.sourceSpan.start.offset,
          end: firstDecl.sourceSpan.end.offset,
          sourceFile: this.sourceMapping.node.getSourceFile(),
        },
      ],
    ),
  );
} else {
  seen.set(block.name, block);
}

if (selectorlessEnabled) {
  if (!metadata.isStandalone) {
    isPoisoned = true;
    diagnostics ??= [];
    diagnostics.push(
      makeDiagnostic(
        ErrorCode.COMPONENT_NOT_STANDALONE,
        component.get('standalone') || node.name,
        `Cannot use selectorless with a component that is not standalone`,
      ),
    );
  } else if (rawImports || rawDeferredImports) {
    isPoisoned = true;
    diagnostics ??= [];
    diagnostics.push(
      makeDiagnostic(
        ErrorCode.UNSUPPORTED_SELECTORLESS_COMPONENT_FIELD,
        (rawImports || rawDeferredImports)!,
        `Cannot use the "${rawImports === null ? 'deferredImports' : 'imports'}" field in a selectorless component`,
      ),
    );
  }
}

if (
  ts.isPropertyAccessExpression(node) &&
  node.expression.kind === ts.SyntaxKind.ThisKeyword &&
  // With the following we make sure we only flag invoked required initializers
  ts.isCallExpression(node.parent) &&
  node.parent.expression === node
) {
  const requiredProp = requiredInitializerDeclarations.find(
    (prop) => prop.name.getText() === node.name.getText(),
  );
  if (requiredProp) {
    const initializerFn = (
      requiredProp.initializer.expression as ts.PropertyAccessExpression
    ).expression.getText();
    diagnostics.push(
      makeDiagnostic(
        ErrorCode.FORBIDDEN_REQUIRED_INITIALIZER_INVOCATION,
        node,
        `\`${node.name.getText()}\` is a required \`${initializerFn}\` and does not have a value in this context.`,
      ),
    );
  }
}

if (attrs) {
  for (let i = 0; i < attrs.length; i += 2) {
    const name = attrs[i];
    const value = attrs[i + 1];

    const terminalValuesMap = this._attrValueMap.get(name)!;
    if (value) {
      result =
        this._matchTerminal(terminalValuesMap, '', cssSelector, matchedCallback) || result;
    }
    result =
      this._matchTerminal(terminalValuesMap, value, cssSelector, matchedCallback) || result;

    const partialValuesMap = this._attrValuePartialMap.get(name)!;
    if (value) {
      result = this._matchPartial(partialValuesMap, '', cssSelector, matchedCallback) || result;
    }
    result =
      this._matchPartial(partialValuesMap, value, cssSelector, matchedCallback) || result;
  }
}

if (variable.name === null) {
  switch (variable.kind) {
    case ir.SemanticVariableKind.Context:
      variable.name = `ctx_r${state.index++}`;
      break;
    case ir.SemanticVariableKind.Identifier:
      // TODO: Prefix increment and `_r` are for compatibility with the old naming scheme.
      // This has the potential to cause collisions when `ctx` is the identifier, so we need a
      // special check for that as well.
      const compatPrefix = variable.identifier === CONTEXT_NAME ? 'i' : '';
      variable.name = `${variable.identifier}_${compatPrefix}r${++state.index}`;
      break;
    default:
      // TODO: Prefix increment for compatibility only.
      variable.name = `_r${++state.index}`;
      break;
  }
}

for (const node of nodes) {
  for (const input of node.inputs) {
    if (input.name === 'ngSwitchCase' && input.value) {
      if (!isNonNullishLiteralAST(input.value)) {
        return false;
      }
    }
  }

  if (node instanceof TmplAstTemplate) {
    for (const attr of node.templateAttrs) {
      if (attr instanceof TmplAstBoundAttribute && attr.name === 'ngSwitchCase' && attr.value) {
        if (!isNonNullishLiteralAST(attr.value)) {
          return false;
        }
      }
    }
  }

  const childHosts = node.children.filter(
    (child): child is TmplAstElement | TmplAstTemplate =>
      child instanceof TmplAstElement || child instanceof TmplAstTemplate,
  );

  if (!allNgSwitchCasesAreLiterals(childHosts)) {
    return false;
  }
}

try {
  const sourceFile = ts.createSourceFile(
    'temp.ts',
    `const obj = ${expr}`,
    ts.ScriptTarget.Latest,
    true,
  );

  const variableStatement = sourceFile.statements[0];
  if (!ts.isVariableStatement(variableStatement)) {
    return null;
  }

  const declaration = variableStatement.declarationList.declarations[0];
  if (!declaration.initializer || !ts.isObjectLiteralExpression(declaration.initializer)) {
    return null;
  }

  // Manage invalid syntax ngClass="{class1 class2}"
  const content = expr.slice(1, -1).trim();
  if (content && !content.includes(':') && content.includes(' ') && !content.includes(',')) {
    return null;
  }

  return declaration.initializer;
} catch (error) {
  return null;
}

const componentImport = route.routeFileImports.find((importDecl) => {
    const clause = importDecl.importClause;
    if (!clause) return false;
    // Default import: import FooComponent from '...'
    if (clause.name && ts.isIdentifier(clause.name) && clause.name.text === componentClassName) {
      return true;
    }
    // Named imports: import { FooComponent } from '...'
    const named = clause.namedBindings;
    if (named && ts.isNamedImports(named)) {
      return named.elements.some((el: ts.ImportSpecifier) => {
        // Support alias: import { Foo as Bar }
        const importedName = el.propertyName ? el.propertyName.text : el.name.text;
        return importedName === componentClassName;
      });
    }
    return false;
  })!;

const transformer: ts.TransformerFactory<ts.Node> = (context) => {
  return (sourceFile) =>
    ts.visitNode(sourceFile, function walk(node: ts.Node): ts.Node {
      if (
        ts.isCallExpression(node) &&
        node.expression.kind === ts.SyntaxKind.ImportKeyword &&
        node.arguments.length > 0 &&
        ts.isStringLiteralLike(node.arguments[0]) &&
        node.arguments[0].text.startsWith('.')
      ) {
        hasChanged = true;
        return context.factory.updateCallExpression(node, node.expression, node.typeArguments, [
          context.factory.createStringLiteral(
            remapRelativeImport(targetFileName, node.arguments[0]),
          ),
          ...node.arguments.slice(1),
        ]);
      }
      return ts.visitEachChild(node, walk, context);
    });
};

deepForEach(sources, (source) => {
  if ((typeof ngDevMode === 'undefined' || ngDevMode) && checkForStandaloneCmp) {
    const cmpDef = getComponentDef(source);
    if (cmpDef?.standalone) {
      throw new RuntimeError(
        RuntimeErrorCode.IMPORT_PROVIDERS_FROM_STANDALONE,
        `Importing providers supports NgModule or ModuleWithProviders but got a standalone component "${stringifyForError(
          source,
        )}"`,
      );
    }
  }

  // Narrow `source` to access the internal type analogue for `ModuleWithProviders`.
  const internalSource = source as Type<unknown> | InjectorTypeWithProviders<unknown>;
  if (walkProviderTree(internalSource, collectProviders, [], dedup)) {
    injectorTypesWithProviders ||= [];
    injectorTypesWithProviders.push(internalSource);
  }
});

if (this.chain === null) {
  const dedupedInterceptorFns = Array.from(
    new Set([
      ...this.injector.get(HTTP_INTERCEPTOR_FNS),
      ...this.injector.get(HTTP_ROOT_INTERCEPTOR_FNS, []),
    ]),
  );

  // Note: interceptors are wrapped right-to-left so that final execution order is
  // left-to-right. That is, if `dedupedInterceptorFns` is the array `[a, b, c]`, we want to
  // produce a chain that is conceptually `c(b(a(end)))`, which we build from the inside
  // out.
  this.chain = dedupedInterceptorFns.reduceRight(
    (nextSequencedFn, interceptorFn) =>
      chainedInterceptorFn(nextSequencedFn, interceptorFn, this.injector),
    interceptorChainEndFn as ChainedInterceptorFn<unknown>,
  );
}

hostMetaMap.forEach((value, key) => {
  // Resolve Enum references to their declared value.
  if (value instanceof EnumValue) {
    value = value.resolved;
  }

  if (typeof key !== 'string') {
    throw createValueHasWrongTypeError(
      hostExpr,
      key,
      `Decorator host metadata must be a string -> string object, but found unparseable key`,
    );
  }

  if (typeof value == 'string') {
    hostMetadata[key] = value;
  } else if (value instanceof DynamicValue) {
    hostMetadata[key] = new WrappedNodeExpr(value.node as ts.Expression);
  } else {
    throw createValueHasWrongTypeError(
      hostExpr,
      value,
      `Decorator host metadata must be a string -> string object, but found unparseable value`,
    );
  }
});

return Object.keys(inputs).reduce<Record<string, R3InputMetadata>>(
  (result, minifiedClassName) => {
    const value = inputs[minifiedClassName];

    // Handle legacy partial input output.
    if (typeof value === 'string' || Array.isArray(value)) {
      result[minifiedClassName] = parseLegacyInputPartialOutput(value);
    } else {
      result[minifiedClassName] = {
        bindingPropertyName: value.publicName,
        classPropertyName: minifiedClassName,
        transformFunction:
          value.transformFunction !== null ? new WrappedNodeExpr(value.transformFunction) : null,
        required: value.isRequired,
        isSignal: value.isSignal,
      };
    }

    return result;
  },
  {},
);

return o.literalMap(
  keys.map((declaredName) => {
    const value = inputs[declaredName];

    return {
      key: declaredName,
      // put quotes around keys that contain potentially unsafe characters
      quoted: isUnsafeObjectKey(declaredName),
      value: o.literalMap([
        {key: 'classPropertyName', quoted: false, value: asLiteral(value.classPropertyName)},
        {key: 'publicName', quoted: false, value: asLiteral(value.bindingPropertyName)},
        {key: 'isSignal', quoted: false, value: asLiteral(value.isSignal)},
        {key: 'isRequired', quoted: false, value: asLiteral(value.required)},
        {key: 'transformFunction', quoted: false, value: value.transformFunction ?? o.NULL_EXPR},
      ]),
    };
  }),
);

return o.literalMap(
  keys.map((declaredName) => {
    const value = inputs[declaredName];
    const publicName = value.bindingPropertyName;
    const differentDeclaringName = publicName !== declaredName;
    let result: o.Expression;

    if (differentDeclaringName || value.transformFunction !== null) {
      const values = [asLiteral(publicName), asLiteral(declaredName)];
      if (value.transformFunction !== null) {
        values.push(value.transformFunction);
      }
      result = o.literalArr(values);
    } else {
      result = asLiteral(publicName);
    }

    return {
      key: declaredName,
      // put quotes around keys that contain potentially unsafe characters
      quoted: isUnsafeObjectKey(declaredName),
      value: result,
    };
  }),
);

import { Injectable } from '@angular/core';
import { MiniStore, Action, MiniState } from 'ngx-bootstrap/mini-ngrx';
import { BsDatepickerState, initialDatepickerState } from './bs-datepicker.state';
import { BehaviorSubject } from 'rxjs';
import { bsDatepickerReducer } from './bs-datepicker.reducer';

@Injectable({providedIn: 'platform'})
export class BsDatepickerStore extends MiniStore<BsDatepickerState> {
  constructor() {
    const _dispatcher = new BehaviorSubject<Action>({
      type: '[datepicker] dispatcher init'
    });
    const state = new MiniState<BsDatepickerState>(
      initialDatepickerState,
      _dispatcher,
      bsDatepickerReducer
    );
    super(_dispatcher, bsDatepickerReducer, state);
  }
}

return async (tree: Tree) => {
  const {buildPaths, testPaths} = await getProjectTsConfigPaths(tree);
  const allPaths = [...new Set([...buildPaths, ...testPaths])];

  for (const tsconfigPath of allPaths) {
    const json = new JSONFile(tree, tsconfigPath);
    const compilerOptions = json.get(['compilerOptions']);

    if (
      !compilerOptions ||
      typeof compilerOptions !== 'object' ||
      Object.keys(compilerOptions).length === 0
    ) {
      continue;
    }

    json.modify(
      ['angularCompilerOptions', 'extendedDiagnostics', 'checks', 'nullishCoalescingNotNullable'],
      'suppress',
    );
    json.modify(
      ['angularCompilerOptions', 'extendedDiagnostics', 'checks', 'optionalChainNotNullable'],
      'suppress',
    );
  }
};

return async (tree) => {
  const {buildPaths, testPaths} = await getProjectTsConfigPaths(tree);
  const allPaths = [...new Set([...buildPaths, ...testPaths])];

  for (const tsconfigPath of allPaths) {
    const json = new JSONFile(tree, tsconfigPath);
    const compilerOptions = json.get(['compilerOptions']);

    if (
      !compilerOptions ||
      typeof compilerOptions !== 'object' ||
      Object.keys(compilerOptions).length === 0
    ) {
      continue;
    }

    const angularOptions = getResolvedAngularCompilerOptions(tree, tsconfigPath);

    if (angularOptions['strictTemplates'] !== undefined) {
      continue;
    }

    if (json.get(['angularCompilerOptions', 'strictTemplates']) === undefined) {
      json.modify(['angularCompilerOptions', 'strictTemplates'], false);
    }
  }
};

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function OnChange(): any {
  const sufix = 'Change';

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return function OnChangeHandler(target: any, propertyKey: string): void {
    const _key = ` __${propertyKey}Value`;
    Object.defineProperty(target, propertyKey, {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      get(): any {
        return this[_key];
      },
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      set(value: any): void {
        const prevValue = this[_key];
        this[_key] = value;
        if (prevValue !== value && this[propertyKey + sufix]) {
          this[propertyKey + sufix].emit(value);
        }
      }
    });
  };
}

if (
  !isCacheActive ||
  requestOptions === false ||
  // Do not cache requests sent with credentials.
  hasOutgoingCredentials(req) ||
  // POST requests are allowed either globally or at request level
  (requestMethod === 'POST' && !globalOptions.includePostRequests && !requestOptions) ||
  (requestMethod !== 'POST' && !ALLOWED_METHODS.includes(requestMethod)) ||
  // Do not cache requests with authentication or cookie headers unless explicitly enabled.
  (!globalOptions.includeRequestsWithAuthHeaders && hasAuthHeaders(req)) ||
  // Do not cache requests that explicitly forbid caching via Cache-Control
  // or Fetch API cache mode.
  hasUncacheableCacheControl(req.headers) ||
  isNonCacheableRequest(req.cache) ||
  globalOptions.filter?.(req) === false
) {
  return false;
}

return initializer.properties.map((prop) => {
  if (!ts.isPropertyAssignment(prop) || !ts.isIdentifier(prop.name)) {
    throw new Error(
      `Property in declaration tagged with "${LITERAL_AS_ENUM_TAG}" must be a property assignment with a static name`,
    );
  }

  if (!ts.isNumericLiteral(prop.initializer) && !ts.isStringLiteralLike(prop.initializer)) {
    throw new Error(
      `Property in declaration tagged with "${LITERAL_AS_ENUM_TAG}" must be initialized to a number or string literal`,
    );
  }

  return {
    name: prop.name.text,
    type: `${declaration.name.getText()}.${prop.name.text}`,
    value: prop.initializer.getText(),
    memberType: MemberType.EnumItem,
    jsdocTags: extractJsDocTags(prop),
    description: extractJsDocDescription(prop),
    memberTags: [],
  };
});

if (ast.value.name === null) {
  if (ast.value.moduleName === null) {
    throw new Error('Invalid import without name nor moduleName');
  }
  result = this.imports.addImport({
    exportModuleSpecifier: ast.value.moduleName,
    exportSymbolName: null,
    requestedFile: this.contextFile,
  });
} else if (ast.value.moduleName !== null) {
  // If a moduleName is specified, this is a normal import. If there's no module name, it's a
  // reference to a global/ambient symbol.
  // This is a normal import. Find the imported module.
  result = this.imports.addImport({
    exportModuleSpecifier: ast.value.moduleName,
    exportSymbolName: ast.value.name,
    requestedFile: this.contextFile,
  });
} else {
  // The symbol is ambient, so just reference it.
  result = this.factory.createIdentifier(ast.value.name);
}

const getInjectorInstance = (
  serializedInjector: SerializedInjector,
  serializedProvider: SerializedProviderRecord,
) => {
  const injector = idToInjector.get(serializedInjector.id)?.deref();
  if (!injector) {
    return;
  }

  const providerRecords = getInjectorProviders(injector);

  if (typeof serializedProvider.index === 'number') {
    const provider = providerRecords[serializedProvider.index];
    return injector.get(provider.token, null, {optional: true});
  } else if (Array.isArray(serializedProvider.index)) {
    const providers = serializedProvider.index.map((index) => providerRecords[index]);
    return injector.get(providers[0].token, null, {optional: true});
  }
  return null;
};

export function getStartingDayOfCalendar(date: Date,
                                         options: { firstDayOfWeek?: number }): Date {
  if (isFirstDayOfWeek(date, options.firstDayOfWeek)) {
    return date;
  }

  const weekDay = getDay(date);
  const offset = calculateDateOffset(weekDay, options.firstDayOfWeek);

  return shiftDate(date, {day: -offset});
}

export function calculateDateOffset(weekday: number, startingDayOffset?: number): number {
  const _startingDayOffset = Number(startingDayOffset);
  if (isNaN(_startingDayOffset)) {
    return 0;
  }

  if (_startingDayOffset === 0) {
    return weekday;
  }

  const offset = weekday - _startingDayOffset % 7;

  return offset < 0 ? offset + 7 : offset;
}
